# Reverse-engineered from writeup description of Kurapica .NET CrackME #15
# The writeup describes the algorithm but does NOT show the actual code/logic.
# What is known:
#   - Username and Company are converted to UPPERCASE
#   - A fixed string 'Kurapica CrackME #15' is also used
#   - The serial must be exactly 16 (0x10) characters long
#   - The serial is generated by a 'simple shuffle of numbers' based on username, company, and the fixed string
#   - Method_35 contains the key generation logic (not shown in writeup)
# All specific shuffle/algorithm steps below are ASSUMPTIONS due to missing code.

FIXED_STRING = 'Kurapica CrackME #15'

def compute_serial(name: str, company: str) -> str:
    """Attempt to reconstruct the serial generation from description.
    The writeup only says it's a 'simple shuffle of numbers' based on
    username, company, and fixed string. The exact algorithm is NOT shown.
    """
    name = name.upper()
    company = company.upper()
    combined = name + company + FIXED_STRING

    # ASSUMPTION: sum or hash of character ordinals drives the serial digits
    # ASSUMPTION: the serial is 16 hex-like or digit characters
    # ASSUMPTION: some simple arithmetic on char codes, then formatted to 16 chars
    val = 0
    for ch in combined:
        val = (val * 31 + ord(ch)) & 0xFFFFFFFFFFFFFFFF  # ASSUMPTION: rolling hash

    # ASSUMPTION: format as 16 uppercase hex digits
    serial = '{:016X}'.format(val & 0xFFFFFFFFFFFFFFFF)
    return serial


def verify(name: str, serial: str) -> bool:
    """Verify a serial for a given name.
    NOTE: company field is required by the real crackme but not exposed here.
    ASSUMPTION: company defaults to empty string if not provided.
    """
    if len(serial) != 16:
        return False
    # ASSUMPTION: company is empty string when not known
    expected = compute_serial(name, '')
    return serial.upper() == expected.upper()


def keygen(name: str, company: str = '') -> str:
    """Generate a serial for the given name and company."""
    return compute_serial(name, company)



# ===== standardized CLI (auto-added) =====
def _cli_norm(_x):
    if isinstance(_x, bytes):
        return _x.hex()
    if isinstance(_x, (list, tuple)):
        return " ".join(_cli_norm(_i) for _i in _x)
    return str(_x)


def _cli_main():
    import sys
    _SAMPLE = ['alice', 'bob', 'Kevin', 'test123', 'admin', 'crackme', 'john_doe', 'w1nner', 'root', 'dragon']
    argv = sys.argv[1:]
    mode = argv[0] if argv else ""
    if mode == "keygen":
        n = 0
        for _nm in _SAMPLE:
            _s = None
            for _call in (lambda: keygen(_nm), lambda: keygen()):
                try:
                    _s = _call()
                    break
                except TypeError:
                    continue
                except Exception:
                    _s = None
                    break
            if _s is None:
                continue
            _sv = _cli_norm(_s)
            print(_nm, _sv)
            n += 1
            if n >= 10:
                break
    elif mode == "verify":
        try:
            print("1" if verify(*argv[1:]) else "0")
        except Exception:
            print("0")
    else:
        sys.stderr.write("usage: {} {{keygen|verify <args>}}\n".format(sys.argv[0]))
        sys.exit(2)


if __name__ == "__main__":
    _cli_main()
